class RedisCacheClient:
    def __init__(self, config: Config):
        self.config = config
        self.client = self._connect()

    def _connect(self) -> RedisCluster:
        startup_nodes = [
            {"host": n["host"], "port": int(n["port"])}
            for n in self.config.REDIS_NODES
        ]
        client = RedisCluster(
            startup_nodes=startup_nodes,
            username=self.config.REDIS_USERNAME,
            password=self.config.REDIS_PASSWORD,
            ssl=self.config.REDIS_SSL,
            ssl_cert_reqs=self.config.REDIS_SSL_CERT_REQS if self.config.REDIS_SSL else None,
            decode_responses=self.config.REDIS_DECODE_RESPONSES,
            socket_timeout=self.config.REDIS_SOCKET_TIMEOUT,
            socket_connect_timeout=self.config.REDIS_SOCKET_CONNECT_TIMEOUT,
            health_check_interval=self.config.REDIS_HEALTH_CHECK_INTERVAL,
            max_connections=self.config.REDIS_MAX_CONNECTIONS,
        )
        client.ping()
        logger.info("Connected to Redis cluster")
        return client

    def health(self) -> bool:
        try:
            return bool(self.client.ping())
        except RedisError as exc:
            logger.error("Redis health check failed: %s", exc)
            return False

    def set_secret(self, key: str, value: Union[str, Dict[str, Any]], ttl: int) -> bool:
        payload = value if isinstance(value, str) else json.dumps(value, separators=(",", ":"))
        return bool(self.client.set(name=key, value=payload, ex=ttl))

    def get_secret(self, key: str) -> Optional[Any]:
        value = self.client.get(key)
        if value is None:
            return None
        try:
            return json.loads(value)
        except (TypeError, json.JSONDecodeError):
            return value

    def delete_secret(self, key: str) -> int:
        return int(self.client.delete(key))

    def ttl(self, key: str) -> int:
        return int(self.client.ttl(key))


